import { GoogleGenAI, Modality } from "@google/genai";

const apiKey = process.env.API_KEY;

// Initialize the client once if possible, but we might need different configs
// We will create instances per request to ensure safety with keys/configs if needed, 
// though the singleton pattern is also fine with the new SDK.
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

interface GeminiRequestOptions {
  modelType: 'fast' | 'balanced' | 'thinking' | 'maps' | 'search';
  systemInstruction?: string;
  location?: { lat: number; lng: number }; // For Maps
}

export interface GeminiResponse {
  text: string;
  groundingMetadata?: any; // For Maps/Search URLs
}

/**
 * Universal Gemini Generator
 */
export const generateGeminiResponse = async (
  prompt: string,
  options: GeminiRequestOptions
): Promise<GeminiResponse> => {
  if (!ai) throw new Error("API Key missing");

  let model = 'gemini-3-flash-preview'; // Default
  let config: any = {
    systemInstruction: options.systemInstruction,
  };

  // Model Selection & Configuration Logic
  switch (options.modelType) {
    case 'fast':
      model = 'gemini-2.5-flash-lite-latest';
      break;

    case 'thinking':
      model = 'gemini-3-pro-preview';
      config.thinkingConfig = { thinkingBudget: 16000 }; // Use a reasonable budget (max is 32k)
      // Note: No maxOutputTokens when using thinking
      break;

    case 'maps':
      model = 'gemini-2.5-flash';
      config.tools = [{ googleMaps: {} }];
      if (options.location) {
        config.toolConfig = {
          retrievalConfig: {
            latLng: {
              latitude: options.location.lat,
              longitude: options.location.lng
            }
          }
        };
      }
      break;

    case 'search':
      model = 'gemini-3-flash-preview';
      config.tools = [{ googleSearch: {} }];
      break;

    case 'balanced':
    default:
      model = 'gemini-3-flash-preview'; // Good balance for general RAG
      break;
  }

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config
    });

    return {
      text: response.text || "No response generated.",
      groundingMetadata: response.candidates?.[0]?.groundingMetadata
    };
  } catch (error) {
    console.error(`Gemini ${options.modelType} Error:`, error);
    return { text: "I encountered an error connecting to the campus network." };
  }
};

/**
 * Text-to-Speech using Gemini 2.5 Flash TTS
 */
export const generateSpeech = async (text: string): Promise<ArrayBuffer | null> => {
  if (!ai) return null;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' },
            },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    // Decode Base64 to ArrayBuffer
    const binaryString = atob(base64Audio);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;

  } catch (error) {
    console.error("TTS Error:", error);
    return null;
  }
};

/**
 * Transcribes audio blob using Gemini 2.5 Flash.
 */
export const transcribeAudio = async (audioBase64: string): Promise<string> => {
  if (!ai) return "Error: API Key missing.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { inlineData: { mimeType: 'audio/wav', data: audioBase64 } },
          { text: "Transcribe the following audio accurately. Output only the transcription." }
        ]
      }
    });

    return response.text?.trim() || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw new Error("Failed to transcribe audio.");
  }
};

import { CAMPUS_DATA } from '../data/campusData';
import { SearchResult, CampusLocation } from '../types';
import { generateGeminiResponse, GeminiResponse } from './geminiService';

const retrieveDocuments = (query: string, customLocations: CampusLocation[] = []): SearchResult[] => {
  const queryTokens = query.toLowerCase().split(/\s+/).filter(t => t.length > 2);
  const results: SearchResult[] = [];
  const allLocations = [...CAMPUS_DATA.locations, ...customLocations];

  allLocations.forEach(loc => {
    let score = 0;
    const content = `Location: ${loc.name}. Type: ${loc.type}. Details: ${loc.description}. Aliases: ${loc.aliases.join(', ')}`;
    const contentLower = content.toLowerCase();
    queryTokens.forEach(token => { if (contentLower.includes(token)) score += 3; });
    if (score > 0) results.push({ content, score, source: 'Location DB' });
  });

  CAMPUS_DATA.routes.forEach(route => {
    let score = 0;
    const fromLoc = allLocations.find(l => l.id === route.fromId)?.name || route.fromId;
    const toLoc = allLocations.find(l => l.id === route.toId)?.name || route.toId;
    const content = `Route: ${fromLoc} to ${toLoc}. Distance: ${route.distance}. Time: ${route.timeWalking}. Shuttle: ${route.shuttleAvailable ? 'Yes' : 'No'}. Details: ${route.description}`;
    const contentLower = content.toLowerCase();
    queryTokens.forEach(token => { if (contentLower.includes(token)) score += 2; });
    if (score > 0) results.push({ content, score, source: 'Route DB' });
  });

  CAMPUS_DATA.generalInfo.forEach(info => {
    let score = 0;
    const infoLower = info.toLowerCase();
    queryTokens.forEach(token => { if (infoLower.includes(token)) score += 1; });
    if (score > 0) results.push({ content: info, score, source: 'General Info' });
  });

  return results.sort((a, b) => b.score - a.score).slice(0, 3);
};

export const processQuery = async (
  userQuery: string, 
  customLocations: CampusLocation[] = [],
  userLocation?: { lat: number, lng: number }
): Promise<{ answer: string; context: string[]; groundingMetadata?: any }> => {

  const lowerQuery = userQuery.toLowerCase();

  // --- INTENT ROUTING ---

  // 1. MAPS/NAVIGATION INTENT
  // Keywords: where is, find, locate, directions, map, near me
  if (lowerQuery.match(/\b(where|find|locate|directions|map|near)\b/)) {
    const response = await generateGeminiResponse(userQuery, {
      modelType: 'maps',
      location: userLocation,
      systemInstruction: "You are a campus guide helper. Use the Google Maps tool to find real-world location info."
    });
    return { answer: response.text, context: ["Used Google Maps Grounding"], groundingMetadata: response.groundingMetadata };
  }

  // 2. SEARCH/NEWS INTENT
  // Keywords: news, latest, event, what happened, online, search
  if (lowerQuery.match(/\b(news|latest|event|happened|search|google)\b/)) {
    const response = await generateGeminiResponse(userQuery, {
      modelType: 'search',
      systemInstruction: "You are a smart assistant. Use Google Search to find the latest information."
    });
    return { answer: response.text, context: ["Used Google Search Grounding"], groundingMetadata: response.groundingMetadata };
  }

  // 3. COMPLEX/REASONING INTENT
  // Keywords: plan, calculate, reason, itinerary, optimize, why
  if (lowerQuery.match(/\b(plan|calculate|itinerary|optimize|compare)\b/) || userQuery.split(' ').length > 15) {
     // Retrieve context first to help the thinking model
     const searchResults = retrieveDocuments(userQuery, customLocations);
     const contextStrings = searchResults.map(r => r.content);
     const prompt = `Context:\n${contextStrings.join('\n')}\n\nQuery: ${userQuery}`;

     const response = await generateGeminiResponse(prompt, {
       modelType: 'thinking',
       systemInstruction: "You are an expert campus planner. Think deeply to provide a comprehensive answer."
     });
     return { answer: response.text, context: [...contextStrings, "Used Gemini 3 Pro Thinking"] };
  }

  // 4. STANDARD RAG (FAST/BALANCED)
  const searchResults = retrieveDocuments(userQuery, customLocations);
  let contextStrings = searchResults.map(r => `[${r.source}] ${r.content}`);

  if (contextStrings.length === 0) {
    contextStrings = ["No local database matches found."];
  }

  const systemInstruction = `
    You are the OAU Campus Guide.
    Answer using the provided context. If unsure, be helpful but admit limitations.
    Keep it concise.
  `;
  const prompt = `Context:\n${contextStrings.join('\n')}\n\nQuestion: ${userQuery}`;

  // Use Lite for very simple greetings, else Balanced (3 Flash)
  const modelType = (userQuery.length < 10 || lowerQuery.match(/\b(hi|hello|hey)\b/)) ? 'fast' : 'balanced';

  const response = await generateGeminiResponse(prompt, {
    modelType,
    systemInstruction
  });

  return {
    answer: response.text,
    context: contextStrings
  };
};

import React, { useState } from 'react';
import { Message } from '../types';
import { generateSpeech } from '../services/geminiService';

interface ChatMessageProps {
  message: Message;
  showDebug: boolean;
}

export const ChatMessage: React.FC<ChatMessageProps> = ({ message, showDebug }) => {
  const isBot = message.role === 'bot';
  const [isPlaying, setIsPlaying] = useState(false);

  const handlePlayTTS = async () => {
    if (isPlaying) return;
    setIsPlaying(true);
    try {
      const audioBuffer = await generateSpeech(message.content);
      if (audioBuffer) {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        const buffer = await ctx.decodeAudioData(audioBuffer);
        const source = ctx.createBufferSource();
        source.buffer = buffer;
        source.connect(ctx.destination);
        source.onended = () => setIsPlaying(false);
        source.start(0);
      } else {
        setIsPlaying(false);
      }
    } catch (e) {
      console.error(e);
      setIsPlaying(false);
    }
  };

  // Helper to render text with markdown-like links or grounding
  const renderContent = () => {
    return (
        <div className="whitespace-pre-wrap">{message.content}</div>
    );
  };

  return (
    <div className={`flex w-full mb-4 ${isBot ? 'justify-start' : 'justify-end'}`}>
      <div className={`max-w-[85%] md:max-w-[70%] flex flex-col ${isBot ? 'items-start' : 'items-end'}`}>

        {/* Message Bubble */}
        <div className={`px-5 py-3 rounded-2xl shadow-sm text-sm md:text-base leading-relaxed relative group ${
          isBot 
            ? 'bg-white border border-gray-200 text-gray-800 rounded-bl-none' 
            : 'bg-blue-600 text-white rounded-br-none'
        }`}>
          {renderContent()}

          {/* TTS Button for Bot */}
          {isBot && (
            <button 
                onClick={handlePlayTTS}
                disabled={isPlaying}
                className="absolute -right-8 top-1/2 -translate-y-1/2 w-6 h-6 rounded-full bg-gray-100 hover:bg-gray-200 text-gray-500 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                title="Read Aloud"
            >
                <i className={`fas ${isPlaying ? 'fa-spinner fa-spin' : 'fa-volume-up'} text-xs`}></i>
            </button>
          )}
        </div>

        {/* Grounding Info (Maps/Search) */}
        {isBot && message.groundingMetadata && (
             <div className="mt-2 text-xs flex flex-wrap gap-2">
                 {message.groundingMetadata.groundingChunks?.map((chunk: any, idx: number) => {
                     if (chunk.web?.uri) {
                         return (
                             <a key={idx} href={chunk.web.uri} target="_blank" rel="noreferrer" className="flex items-center gap-1 bg-white border border-gray-200 px-2 py-1 rounded-full text-blue-600 hover:bg-blue-50 transition-colors">
                                 <i className="fas fa-globe"></i> {chunk.web.title || 'Source'}
                             </a>
                         );
                     }
                     return null;
                 })}
             </div>
        )}

        {/* Timestamp */}
        <span className="text-[10px] text-gray-400 mt-1 px-1">
          {new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
          {isBot && ' • UniNav Bot'}
        </span>

        {/* Academic Context Display */}
        {isBot && showDebug && message.retrievedContext && message.retrievedContext.length > 0 && (
          <div className="mt-2 p-3 bg-slate-100 border border-slate-300 rounded-lg text-xs w-full text-left animate-in fade-in duration-300">
            <div className="flex items-center gap-2 mb-1 text-slate-500 font-bold uppercase tracking-wider text-[10px]">
              <i className="fas fa-database"></i> Source Context
            </div>
            <ul className="list-disc list-inside space-y-1 text-slate-600 font-mono">
              {message.retrievedContext.map((ctx, idx) => (
                <li key={idx} className="line-clamp-2 hover:line-clamp-none cursor-pointer transition-all">
                  {ctx}
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';

interface LiveAPIProps {
  onClose: () => void;
}

export const LiveAPI: React.FC<LiveAPIProps> = ({ onClose }) => {
  const [status, setStatus] = useState<'connecting' | 'connected' | 'error'>('connecting');
  const [volume, setVolume] = useState(0);

  // Refs for audio handling to avoid re-renders
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);

  // Output Audio
  const nextStartTimeRef = useRef<number>(0);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Connection
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    const startSession = async () => {
      try {
        const apiKey = process.env.API_KEY;
        if (!apiKey) throw new Error("No API Key");

        const ai = new GoogleGenAI({ apiKey });

        // Setup Audio Contexts
        const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        audioContextRef.current = inputCtx;
        outputAudioContextRef.current = outputCtx;

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        streamRef.current = stream;

        // Connect to Live API
        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-12-2025',
          callbacks: {
            onopen: () => {
              setStatus('connected');

              // Setup Input Processing
              const source = inputCtx.createMediaStreamSource(stream);
              sourceRef.current = source;

              const processor = inputCtx.createScriptProcessor(4096, 1, 1);
              processorRef.current = processor;

              processor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);

                // Volume viz
                let sum = 0;
                for(let i=0; i<inputData.length; i++) sum += inputData[i]*inputData[i];
                setVolume(Math.sqrt(sum/inputData.length));

                // Send to Gemini
                const pcmBlob = createBlob(inputData);
                sessionPromise.then(session => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              };

              source.connect(processor);
              processor.connect(inputCtx.destination);
            },
            onmessage: async (msg: LiveServerMessage) => {
              const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
              if (audioData) {
                // Play Audio
                const ctx = outputAudioContextRef.current;
                if (!ctx) return;

                const binary = atob(audioData);
                const bytes = new Uint8Array(binary.length);
                for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);

                // Decode raw PCM? The examples use `decodeAudioData` wrapper for PCM arrays
                // But the example provided in instructions uses custom decode.
                // Let's use the provided `decodeAudioData` pattern from instructions.
                const buffer = await decodeAudioData(bytes, ctx, 24000, 1);

                const src = ctx.createBufferSource();
                src.buffer = buffer;
                src.connect(ctx.destination);

                // Scheduling
                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
                src.start(nextStartTimeRef.current);
                nextStartTimeRef.current += buffer.duration;

                sourcesRef.current.add(src);
                src.onended = () => sourcesRef.current.delete(src);
              }

              if (msg.serverContent?.interrupted) {
                 sourcesRef.current.forEach(s => s.stop());
                 sourcesRef.current.clear();
                 nextStartTimeRef.current = 0;
              }
            },
            onclose: () => setStatus('error'),
            onerror: () => setStatus('error')
          },
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
              voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
            },
            systemInstruction: "You are a helpful OAU Campus guide. Chat naturally with the student."
          }
        });

        sessionRef.current = sessionPromise;

      } catch (e) {
        console.error(e);
        setStatus('error');
      }
    };

    startSession();

    return () => {
      // Cleanup
      streamRef.current?.getTracks().forEach(t => t.stop());
      processorRef.current?.disconnect();
      sourceRef.current?.disconnect();
      audioContextRef.current?.close();
      outputAudioContextRef.current?.close();
      // Cannot explicitly close session in SDK currently easily without keeping ref? 
      // The guidelines say "Use session.close()". 
      // sessionPromise returns a session object.
      sessionRef.current?.then((s: any) => s.close());
    };
  }, []);

  return (
    <div className="fixed inset-0 z-50 bg-black/90 flex flex-col items-center justify-center text-white backdrop-blur-md">
       <button onClick={onClose} className="absolute top-6 right-6 p-4 text-white/50 hover:text-white">
         <i className="fas fa-times text-2xl"></i>
       </button>

       <div className="flex flex-col items-center gap-8">
          <div className={`w-32 h-32 rounded-full flex items-center justify-center transition-all duration-100 ${
             status === 'connected' ? 'bg-blue-600 shadow-[0_0_50px_rgba(37,99,235,0.5)]' : 'bg-gray-700'
          }`}
          style={{ transform: `scale(${1 + volume * 2})` }}
          >
             <i className={`fas ${status === 'connecting' ? 'fa-spinner fa-spin' : 'fa-microphone'} text-4xl`}></i>
          </div>

          <div className="text-center">
            <h2 className="text-2xl font-bold mb-2">Live Voice Chat</h2>
            <p className="text-gray-400">
              {status === 'connecting' ? 'Connecting to Gemini...' : 
               status === 'connected' ? 'Listening...' : 'Connection Error'}
            </p>
          </div>
       </div>
    </div>
  );
};

// Utils
function createBlob(data: Float32Array) {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  let binary = '';
  const bytes = new Uint8Array(int16.buffer);
  for(let i=0; i<bytes.length; i++) binary += String.fromCharCode(bytes[i]);
  const b64 = btoa(binary);

  return {
    data: b64,
    mimeType: 'audio/pcm;rate=16000',
  };
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export interface Message {
  id: string;
  role: 'user' | 'bot';
  content: string;
  timestamp: number;
  retrievedContext?: string[]; // To show what the RAG system found
  groundingMetadata?: any; // For Maps/Search links
}

export interface CampusLocation {
  id: string;
  name: string;
  aliases: string[];
  type: 'academic' | 'facility' | 'transport' | 'residential' | 'custom';
  description: string;
  coords: { x: number; y: number }; // Percentage 0-100
}

export interface RouteInfo {
  id: string;
  fromId: string;
  toId: string;
  distance: string; // e.g., "500m"
  timeWalking: string; // e.g., "6 mins"
  shuttleAvailable: boolean;
  shuttleFare?: string;
  description: string;
}

// The structure of our Knowledge Base
export interface KnowledgeBase {
  locations: CampusLocation[];
  routes: RouteInfo[];
  generalInfo: string[]; // General rules, opening hours, etc.
