import { GoogleGenAI, Modality } from "@google/genai";

const apiKey = process.env.API_KEY;

// Initialize the client once if possible, but we might need different configs
// We will create instances per request to ensure safety with keys/configs if needed, 
// though the singleton pattern is also fine with the new SDK.
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

interface GeminiRequestOptions {
  modelType: 'fast' | 'balanced' | 'thinking' | 'maps' | 'search';
  systemInstruction?: string;
  location?: { lat: number; lng: number }; // For Maps
}

export interface GeminiResponse {
  text: string;
  groundingMetadata?: any; // For Maps/Search URLs
}

/**
 * Universal Gemini Generator
 */
export const generateGeminiResponse = async (
  prompt: string,
  options: GeminiRequestOptions
): Promise<GeminiResponse> => {
  if (!ai) throw new Error("API Key missing");

  let model = 'gemini-3-flash-preview'; // Default
  let config: any = {
    systemInstruction: options.systemInstruction,
  };

  // Model Selection & Configuration Logic
  switch (options.modelType) {
    case 'fast':
      model = 'gemini-2.5-flash-lite-latest';
      break;

    case 'thinking':
      model = 'gemini-3-pro-preview';
      config.thinkingConfig = { thinkingBudget: 16000 }; // Use a reasonable budget (max is 32k)
      // Note: No maxOutputTokens when using thinking
      break;

    case 'maps':
      model = 'gemini-2.5-flash';
      config.tools = [{ googleMaps: {} }];
      if (options.location) {
        config.toolConfig = {
          retrievalConfig: {
            latLng: {
              latitude: options.location.lat,
              longitude: options.location.lng
            }
          }
        };
      }
      break;

    case 'search':
      model = 'gemini-3-flash-preview';
      config.tools = [{ googleSearch: {} }];
      break;

    case 'balanced':
    default:
      model = 'gemini-3-flash-preview'; // Good balance for general RAG
      break;
  }

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config
    });

    return {
      text: response.text || "No response generated.",
      groundingMetadata: response.candidates?.[0]?.groundingMetadata
    };
  } catch (error) {
    console.error(`Gemini ${options.modelType} Error:`, error);
    return { text: "I encountered an error connecting to the campus network." };
  }
};

/**
 * Text-to-Speech using Gemini 2.5 Flash TTS
 */
export const generateSpeech = async (text: string): Promise<ArrayBuffer | null> => {
  if (!ai) return null;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' },
            },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    // Decode Base64 to ArrayBuffer
    const binaryString = atob(base64Audio);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;

  } catch (error) {
    console.error("TTS Error:", error);
    return null;
  }
};

/**
 * Decodes Raw PCM Data (Int16) to an AudioBuffer for playback.
 * Used for both TTS and Live API audio.
 */
export const decodePCMToAudioBuffer = (
  pcmData: ArrayBuffer, 
  audioCtx: AudioContext, 
  sampleRate: number = 24000
): AudioBuffer => {
  // Ensure we have an even number of bytes for Int16
  let buffer = pcmData;
  if (buffer.byteLength % 2 !== 0) {
      buffer = buffer.slice(0, buffer.byteLength - 1);
  }

  const dataInt16 = new Int16Array(buffer);
  const numChannels = 1;
  const frameCount = dataInt16.length;

  const audioBuffer = audioCtx.createBuffer(numChannels, frameCount, sampleRate);
  const channelData = audioBuffer.getChannelData(0);

  // Convert Int16 to Float32 [-1.0, 1.0]
  for (let i = 0; i < frameCount; i++) {
    channelData[i] = dataInt16[i] / 32768.0;
  }

  return audioBuffer;
}

/**
 * Transcribes audio blob using Gemini 2.5 Flash.
 */
export const transcribeAudio = async (audioBase64: string): Promise<string> => {
  if (!ai) return "Error: API Key missing.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { inlineData: { mimeType: 'audio/wav', data: audioBase64 } },
          { text: "Transcribe the following audio accurately. Output only the transcription." }
        ]
      }
    });

    return response.text?.trim() || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw new Error("Failed to transcribe audio.");
  }
};

