import { CAMPUS_DATA } from '../data/campusData';
import { SearchResult, CampusLocation } from '../types';
import { generateGeminiResponse, GeminiResponse } from './geminiService';

const retrieveDocuments = (query: string, customLocations: CampusLocation[] = []): SearchResult[] => {
  const queryTokens = query.toLowerCase().split(/\s+/).filter(t => t.length > 2);
  const results: SearchResult[] = [];
  const allLocations = [...CAMPUS_DATA.locations, ...customLocations];

  allLocations.forEach(loc => {
    let score = 0;
    const content = `Location: ${loc.name}. Type: ${loc.type}. Details: ${loc.description}. Aliases: ${loc.aliases.join(', ')}`;
    const contentLower = content.toLowerCase();
    queryTokens.forEach(token => { if (contentLower.includes(token)) score += 3; });
    if (score > 0) results.push({ content, score, source: 'Location DB' });
  });

  CAMPUS_DATA.routes.forEach(route => {
    let score = 0;
    const fromLoc = allLocations.find(l => l.id === route.fromId)?.name || route.fromId;
    const toLoc = allLocations.find(l => l.id === route.toId)?.name || route.toId;
    const content = `Route: ${fromLoc} to ${toLoc}. Distance: ${route.distance}. Time: ${route.timeWalking}. Shuttle: ${route.shuttleAvailable ? 'Yes' : 'No'}. Details: ${route.description}`;
    const contentLower = content.toLowerCase();
    queryTokens.forEach(token => { if (contentLower.includes(token)) score += 2; });
    if (score > 0) results.push({ content, score, source: 'Route DB' });
  });

  CAMPUS_DATA.generalInfo.forEach(info => {
    let score = 0;
    const infoLower = info.toLowerCase();
    queryTokens.forEach(token => { if (infoLower.includes(token)) score += 1; });
    if (score > 0) results.push({ content: info, score, source: 'General Info' });
  });

  return results.sort((a, b) => b.score - a.score).slice(0, 3);
};

const findLocationInQuery = (query: string, locations: CampusLocation[]): string | undefined => {
  const lowerQuery = query.toLowerCase();
  // Sort by name length descending to match specific names before substrings if any
  const sorted = [...locations].sort((a,b) => b.name.length - a.name.length);

  for (const loc of sorted) {
    if (lowerQuery.includes(loc.name.toLowerCase())) return loc.id;
    for (const alias of loc.aliases) {
      if (lowerQuery.includes(alias.toLowerCase())) return loc.id;
    }
  }
  return undefined;
};

export const processQuery = async (
  userQuery: string, 
  customLocations: CampusLocation[] = [],
  userLocation?: { lat: number, lng: number }
): Promise<{ answer: string; context: string[]; groundingMetadata?: any; suggestedLocationId?: string }> => {

  const lowerQuery = userQuery.toLowerCase();
  const allLocations = [...CAMPUS_DATA.locations, ...customLocations];
  const suggestedLocationId = findLocationInQuery(userQuery, allLocations);

  // --- INTENT ROUTING ---

  // 1. MAPS/NAVIGATION INTENT
  // Keywords: where is, find, locate, directions, map, near me
  if (lowerQuery.match(/\b(where|find|locate|directions|map|near)\b/)) {
    const response = await generateGeminiResponse(userQuery, {
      modelType: 'maps',
      location: userLocation,
      systemInstruction: "You are a campus guide helper. Use the Google Maps tool to find real-world location info."
    });
    return { 
        answer: response.text, 
        context: ["Used Google Maps Grounding"], 
        groundingMetadata: response.groundingMetadata,
        suggestedLocationId 
    };
  }

  // 2. SEARCH/NEWS INTENT
  // Keywords: news, latest, event, what happened, online, search
  if (lowerQuery.match(/\b(news|latest|event|happened|search|google)\b/)) {
    const response = await generateGeminiResponse(userQuery, {
      modelType: 'search',
      systemInstruction: "You are a smart assistant. Use Google Search to find the latest information."
    });
    return { 
        answer: response.text, 
        context: ["Used Google Search Grounding"], 
        groundingMetadata: response.groundingMetadata,
        suggestedLocationId
    };
  }

  // 3. COMPLEX/REASONING INTENT
  // Keywords: plan, calculate, reason, itinerary, optimize, why
  if (lowerQuery.match(/\b(plan|calculate|itinerary|optimize|compare)\b/) || userQuery.split(' ').length > 15) {
     // Retrieve context first to help the thinking model
     const searchResults = retrieveDocuments(userQuery, customLocations);
     const contextStrings = searchResults.map(r => r.content);
     const prompt = `Context:\n${contextStrings.join('\n')}\n\nQuery: ${userQuery}`;

     const response = await generateGeminiResponse(prompt, {
       modelType: 'thinking',
       systemInstruction: "You are an expert campus planner. Think deeply to provide a comprehensive answer."
     });
     return { 
         answer: response.text, 
         context: [...contextStrings, "Used Gemini 3 Pro Thinking"],
         suggestedLocationId
     };
  }

  // 4. STANDARD RAG (FAST/BALANCED)
  const searchResults = retrieveDocuments(userQuery, customLocations);
  let contextStrings = searchResults.map(r => `[${r.source}] ${r.content}`);

  if (contextStrings.length === 0) {
    contextStrings = ["No local database matches found."];
  }

  const systemInstruction = `
    You are the OAU Campus Guide.
    Answer using the provided context. If unsure, be helpful but admit limitations.
    Keep it concise.
  `;
  const prompt = `Context:\n${contextStrings.join('\n')}\n\nQuestion: ${userQuery}`;

  // Use Lite for very simple greetings, else Balanced (3 Flash)
  const modelType = (userQuery.length < 10 || lowerQuery.match(/\b(hi|hello|hey)\b/)) ? 'fast' : 'balanced';

  const response = await generateGeminiResponse(prompt, {
    modelType,
    systemInstruction
  });

  return {
    answer: response.text,
    context: contextStrings,
    suggestedLocationId
  };
};

import React, { useState, useRef, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Message, CampusLocation } from './types';
import { processQuery } from './services/ragService';
import { transcribeAudio } from './services/geminiService';
import { ChatMessage } from './components/ChatMessage';
import { InputArea } from './components/InputArea';
import { CampusMap } from './components/CampusMap';
import { CAMPUS_DATA } from './data/campusData';
import { LiveAPI } from './components/LiveAPI';

// Robust Local Storage Hook
const useLocalStorage = <T,>(key: string, initialValue: T): [T, React.Dispatch<React.SetStateAction<T>>] => {
  // 1. Initialize state lazily
  const [value, setValue] = useState<T>(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.error(`Error reading ${key} from localStorage`, error);
      return initialValue;
    }
  });

  // 2. Sync to localStorage whenever value changes
  useEffect(() => {
    try {
      window.localStorage.setItem(key, JSON.stringify(value));
    } catch (error) {
      console.error(`Error writing ${key} to localStorage`, error);
    }
  }, [key, value]);

  return [value, setValue];
};

const App: React.FC = () => {
  // State: Messages (Persisted)
  const [messages, setMessages] = useLocalStorage<Message[]>('uninav_history_v2', [
    {
      id: '1',
      role: 'bot',
      content: "Welcome to OAU! I can help you find the Senate Building, Moremi Hall, or check the latest news. Type or speak to start!",
      timestamp: Date.now()
    }
  ]);

  // State: Locations (Persisted + Dynamic)
  const [locations, setLocations] = useLocalStorage<CampusLocation[]>('uninav_locations_v2', CAMPUS_DATA.locations);

  // UI State
  const [isLoading, setIsLoading] = useState(false);
  const [showDebug, setShowDebug] = useState(true);
  const [voiceMode, setVoiceMode] = useState(false); // Legacy TTS toggle
  const [isLiveActive, setIsLiveActive] = useState(false); // Live API
  const [isAddingLandmark, setIsAddingLandmark] = useState<{x: number, y: number} | null>(null);
  const [newLandmarkName, setNewLandmarkName] = useState("");
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | undefined>(undefined);
  const [activeDestination, setActiveDestination] = useState<CampusLocation | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Get Geolocation on mount for Maps Grounding & Navigation
  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.watchPosition(
        (pos) => setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        (err) => console.log("Geolocation denied or error", err),
        { enableHighAccuracy: true }
      );
    }
  }, []);

  const processUserRequest = async (text: string) => {
     // 1. Add User Message
     const userMsg: Message = {
      id: uuidv4(),
      role: 'user',
      content: text,
      timestamp: Date.now()
    };

    // IMPORTANT: Update state immediately
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      // 2. Process via RAG/Gemini Service with Routing
      const { answer, context, groundingMetadata, suggestedLocationId } = await processQuery(text, locations, userLocation);

      // 2.1 Update Map if location detected in text
      if (suggestedLocationId) {
          const loc = locations.find(l => l.id === suggestedLocationId);
          if (loc) {
              setActiveDestination(loc);
          }
      }

      // 3. Add Bot Message
      const botMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: answer,
        timestamp: Date.now(),
        retrievedContext: context,
        groundingMetadata
      };

      setMessages(prev => [...prev, botMsg]);

    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: "System Error: Unable to process request.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAudioSend = async (audioBlob: Blob) => {
    setIsLoading(true);
    const tempId = uuidv4();
    setMessages(prev => [...prev, { id: tempId, role: 'user', content: "🎤 Processing audio...", timestamp: Date.now() }]);

    try {
      const reader = new FileReader();
      reader.readAsDataURL(audioBlob);
      reader.onloadend = async () => {
        const base64Data = (reader.result as string).split(',')[1];
        const transcription = await transcribeAudio(base64Data);

        // Update the placeholder message
        setMessages(prev => prev.map(m => m.id === tempId ? { ...m, content: `🎤 "${transcription}"` } : m));

        if (!transcription) {
          setIsLoading(false);
          return;
        }

        // Logic similar to processUserRequest but without re-adding user message
        const { answer, context, groundingMetadata, suggestedLocationId } = await processQuery(transcription, locations, userLocation);

        if (suggestedLocationId) {
            const loc = locations.find(l => l.id === suggestedLocationId);
            if (loc) setActiveDestination(loc);
        }

        const botMsg: Message = {
            id: uuidv4(),
            role: 'bot',
            content: answer,
            timestamp: Date.now(),
            retrievedContext: context,
            groundingMetadata
        };
        setMessages(prev => [...prev, botMsg]);
        setIsLoading(false);
      };
    } catch (e) {
      console.error(e);
      setIsLoading(false);
    }
  };

  // --- Map Interactions ---

  const handleLocationClick = (loc: CampusLocation) => {
    // Set destination for blue line routing
    setActiveDestination(loc);

    // Also trigger chat info
    processUserRequest(`Tell me about ${loc.name} and how to get there.`);
  };

  const handleMapClick = (x: number, y: number) => {
    setIsAddingLandmark({ x, y });
    setNewLandmarkName("");
  };

  const saveLandmark = () => {
    if (isAddingLandmark && newLandmarkName.trim()) {
      const newLoc: CampusLocation = {
        id: `custom_${uuidv4()}`,
        name: newLandmarkName,
        aliases: [],
        type: 'custom',
        description: `A custom landmark added by the user at ${newLandmarkName}.`,
        coords: isAddingLandmark
        // Custom landmarks lack real lat/lng unless we implement a picker, so nav won't work for them yet.
      };
      setLocations([...locations, newLoc]);
      setIsAddingLandmark(null);

      const msg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: `I've added "${newLandmarkName}" to the map.`,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, msg]);
    }
  };

  const clearHistory = () => {
    if(confirm("Clear chat history?")) {
      setMessages([]);
      // Force reload to clear any memory state if needed, though strictly not required with proper react state
      // window.location.reload(); 
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50 md:flex-row font-sans">

      {/* Live API Overlay */}
      {isLiveActive && <LiveAPI onClose={() => setIsLiveActive(false)} />}

      {/* Left Panel: Map & Tools */}
      <div className="w-full md:w-1/3 bg-white border-b md:border-b-0 md:border-r border-gray-200 flex flex-col shadow-lg z-10">
         <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-blue-600 text-white">
             <div className="flex items-center gap-2">
                <i className="fas fa-university text-xl"></i>
                <h1 className="font-bold text-lg">OAU UniNav</h1>
             </div>
             <button onClick={clearHistory} className="text-blue-100 hover:text-white" title="Clear History">
               <i className="fas fa-trash"></i>
             </button>
         </div>

         <div className="p-4 flex-grow overflow-y-auto">
            <h2 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Ile-Ife Campus Map</h2>
            <CampusMap 
              locations={locations} 
              onLocationClick={handleLocationClick}
              onMapClick={handleMapClick}
              userLocation={userLocation}
              activeDestination={activeDestination}
            />

            {/* Add Landmark Form */}
            {isAddingLandmark && (
              <div className="mt-4 p-3 bg-blue-50 border border-blue-200 rounded-lg animate-in slide-in-from-top-2">
                <h3 className="text-sm font-bold text-blue-800 mb-2">New Landmark</h3>
                <input 
                  autoFocus
                  type="text" 
                  value={newLandmarkName}
                  onChange={e => setNewLandmarkName(e.target.value)}
                  placeholder="Enter Name..."
                  className="w-full text-sm border-gray-300 rounded-md mb-2 p-2"
                />
                <div className="flex gap-2">
                  <button onClick={saveLandmark} className="flex-1 bg-blue-600 text-white text-xs py-1.5 rounded hover:bg-blue-700">Save</button>
                  <button onClick={() => setIsAddingLandmark(null)} className="flex-1 bg-gray-200 text-gray-600 text-xs py-1.5 rounded hover:bg-gray-300">Cancel</button>
                </div>
              </div>
            )}

            {/* Start Live Call CTA */}
            <div className="mt-6">
                <button 
                  onClick={() => setIsLiveActive(true)}
                  className="w-full py-3 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-xl shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-2 group"
                >
                    <div className="w-2 h-2 bg-red-400 rounded-full animate-pulse"></div>
                    <span className="font-bold">Start Live Voice Chat</span>
                    <i className="fas fa-arrow-right group-hover:translate-x-1 transition-transform"></i>
                </button>
                <p className="text-[10px] text-center text-gray-400 mt-2">Powered by Gemini 2.5 Native Audio</p>
            </div>
         </div>

         <div className="p-4 border-t border-gray-100 hidden md:block">
            <div className="flex flex-col gap-2">
              <button
                onClick={() => setShowDebug(!showDebug)}
                className={`flex items-center justify-between p-2 rounded text-xs font-medium transition-colors ${
                  showDebug ? 'bg-slate-100 text-slate-700' : 'text-gray-400 hover:bg-gray-50'
                }`}
              >
                <span>Show AI Thought Process</span>
                <i className={`fas ${showDebug ? 'fa-toggle-on text-blue-500' : 'fa-toggle-off'}`}></i>
              </button>
            </div>
         </div>
      </div>

      {/* Right Panel: Chat */}
      <div className="flex-1 flex flex-col h-[60vh] md:h-full relative bg-gray-50">
        <div className="flex-1 overflow-y-auto p-4 scroll-smooth">
          {messages.map(msg => (
            <ChatMessage key={msg.id} message={msg} showDebug={showDebug} />
          ))}
          {isLoading && (
            <div className="flex justify-start mb-4">
               <div className="bg-white border border-gray-200 px-4 py-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-2">
