import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';

interface LiveAPIProps {
  onClose: () => void;
  onTranscript: (role: 'user' | 'bot', text: string) => void;
}

export const LiveAPI: React.FC<LiveAPIProps> = ({ onClose, onTranscript }) => {
  const [status, setStatus] = useState<'connecting' | 'connected' | 'error'>('connecting');
  const [volume, setVolume] = useState(0);

  // Refs for audio handling to avoid re-renders
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);

  // Output Audio
  const nextStartTimeRef = useRef<number>(0);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Transcription Accumulators
  const inputTranscriptRef = useRef("");
  const outputTranscriptRef = useRef("");

  // Connection
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    const startSession = async () => {
      try {
        const apiKey = process.env.API_KEY;
        if (!apiKey) throw new Error("No API Key");

        const ai = new GoogleGenAI({ apiKey });

        // Setup Audio Contexts
        const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        audioContextRef.current = inputCtx;
        outputAudioContextRef.current = outputCtx;

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        streamRef.current = stream;

        // Connect to Live API
        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-12-2025',
          callbacks: {
            onopen: () => {
              setStatus('connected');

              // Setup Input Processing
              const source = inputCtx.createMediaStreamSource(stream);
              sourceRef.current = source;

              const processor = inputCtx.createScriptProcessor(4096, 1, 1);
              processorRef.current = processor;

              processor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);

                // Volume viz
                let sum = 0;
                for(let i=0; i<inputData.length; i++) sum += inputData[i]*inputData[i];
                setVolume(Math.sqrt(sum/inputData.length));

                // Send to Gemini
                const pcmBlob = createBlob(inputData);
                sessionPromise.then(session => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              };

              source.connect(processor);
              processor.connect(inputCtx.destination);
            },
            onmessage: async (msg: LiveServerMessage) => {
              const { serverContent } = msg;

              // 1. Handle Transcriptions
              if (serverContent?.inputTranscription?.text) {
                inputTranscriptRef.current += serverContent.inputTranscription.text;
              }
              if (serverContent?.outputTranscription?.text) {
                outputTranscriptRef.current += serverContent.outputTranscription.text;
              }

              // 2. Commit Transcripts on Turn Complete
              if (serverContent?.turnComplete) {
                if (inputTranscriptRef.current.trim()) {
                   onTranscript('user', inputTranscriptRef.current.trim());
                   inputTranscriptRef.current = "";
                }
                if (outputTranscriptRef.current.trim()) {
                   onTranscript('bot', outputTranscriptRef.current.trim());
                   outputTranscriptRef.current = "";
                }
              }

              // 3. Handle Audio Output
              const audioData = serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
              if (audioData) {
                const ctx = outputAudioContextRef.current;
                if (!ctx) return;

                const binary = atob(audioData);
                const bytes = new Uint8Array(binary.length);
                for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);

                const buffer = await decodeAudioData(bytes, ctx, 24000, 1);

                const src = ctx.createBufferSource();
                src.buffer = buffer;
                src.connect(ctx.destination);

                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
                src.start(nextStartTimeRef.current);
                nextStartTimeRef.current += buffer.duration;

                sourcesRef.current.add(src);
                src.onended = () => sourcesRef.current.delete(src);
              }

              if (serverContent?.interrupted) {
                 sourcesRef.current.forEach(s => s.stop());
                 sourcesRef.current.clear();
                 nextStartTimeRef.current = 0;

                 // Optional: Commit whatever we have so far if interrupted
                 if (inputTranscriptRef.current.trim()) {
                    onTranscript('user', inputTranscriptRef.current.trim() + " [Interrupted]");
                    inputTranscriptRef.current = "";
                 }
                 if (outputTranscriptRef.current.trim()) {
                    onTranscript('bot', outputTranscriptRef.current.trim() + " [Interrupted]");
                    outputTranscriptRef.current = "";
                 }
              }
            },
            onclose: () => setStatus('error'),
            onerror: () => setStatus('error')
          },
          config: {
            responseModalities: [Modality.AUDIO],
            // Enable transcription
            inputAudioTranscription: {}, 
            outputAudioTranscription: {},
            speechConfig: {
              voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
            },
            systemInstruction: "You are a helpful OAU Campus guide. Chat naturally with the student. Keep answers concise."
          }
        });

        sessionRef.current = sessionPromise;

      } catch (e) {
        console.error(e);
        setStatus('error');
      }
    };

    startSession();

    return () => {
      // Cleanup
      streamRef.current?.getTracks().forEach(t => t.stop());
      processorRef.current?.disconnect();
      sourceRef.current?.disconnect();
      audioContextRef.current?.close();
      outputAudioContextRef.current?.close();
      sessionRef.current?.then((s: any) => s.close());
    };
  }, [onTranscript]);

  return (
    <div className="fixed inset-0 z-50 bg-black/90 flex flex-col items-center justify-center text-white backdrop-blur-md">
       <button onClick={onClose} className="absolute top-6 right-6 p-4 text-white/50 hover:text-white">
         <i className="fas fa-times text-2xl"></i>
       </button>

       <div className="flex flex-col items-center gap-8">
          <div className={`w-32 h-32 rounded-full flex items-center justify-center transition-all duration-100 ${
             status === 'connected' ? 'bg-blue-600 shadow-[0_0_50px_rgba(37,99,235,0.5)]' : 'bg-gray-700'
          }`}
          style={{ transform: `scale(${1 + volume * 2})` }}
          >
             <i className={`fas ${status === 'connecting' ? 'fa-spinner fa-spin' : 'fa-microphone'} text-4xl`}></i>
          </div>

          <div className="text-center">
            <h2 className="text-2xl font-bold mb-2">Live Voice Chat</h2>
            <p className="text-gray-400">
              {status === 'connecting' ? 'Connecting to Gemini...' : 
               status === 'connected' ? 'Listening...' : 'Connection Error'}
            </p>
            <p className="text-xs text-gray-500 mt-4">Transcripts are saved to chat.</p>
          </div>
       </div>
    </div>
  );
};

// Utils
function createBlob(data: Float32Array) {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  let binary = '';
  const bytes = new Uint8Array(int16.buffer);
  for(let i=0; i<bytes.length; i++) binary += String.fromCharCode(bytes[i]);
  const b64 = btoa(binary);

  return {
    data: b64,
    mimeType: 'audio/pcm;rate=16000',
  };
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

