                className="w-full h-full opacity-90 hover:opacity-100 transition-opacity"
             ></iframe>

             {/* Status Badge */}
             <div className="absolute bottom-2 right-2 bg-white/90 backdrop-blur px-2 py-1 rounded text-[10px] text-blue-600 border border-blue-100 font-medium pointer-events-none flex items-center gap-1">
                {userLocation && activeDestination 
                    ? <><i className="fas fa-route"></i> Live Directions (Blue Line)</> 
                    : userLocation 
                        ? <><i className="fas fa-location-arrow"></i> Your Location</>
                        : "Satellite View"}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { CampusLocation } from '../types';

interface CampusMapProps {
  locations: CampusLocation[];
  onLocationClick: (loc: CampusLocation) => void;
  onMapClick: (x: number, y: number) => void;
  userLocation?: { lat: number; lng: number };
  activeDestination?: CampusLocation | null;
}

export const CampusMap: React.FC<CampusMapProps> = ({ 
  locations, 
  onLocationClick, 
  onMapClick,
  userLocation,
  activeDestination
}) => {
  const [viewMode, setViewMode] = useState<'schematic' | 'google'>('schematic');
  const [isExpanded, setIsExpanded] = useState(false);
  const prevDestRef = useRef<string | undefined>(undefined);

  // Auto-switch to Google Maps view when destination changes via Chat
  useEffect(() => {
    // Only switch if we have a valid destination, a valid user location, and the destination ID has actually changed
    if (activeDestination && activeDestination.id !== prevDestRef.current && userLocation) {
        setViewMode('google');
    }
    prevDestRef.current = activeDestination?.id;
  }, [activeDestination, userLocation]);

  // Calibrated projection based on key landmarks (Senate & Moremi/Awolowo)
  // Maps real Lat/Lng to the 0-100% SVG coordinate space of the schematic
  const userProjected = useMemo(() => {
    if (!userLocation) return null;

    // Linear interpolation based on reference points:
    // Lat: Senate (7.5197) -> Y:10, MotionGround (7.5100) -> Y:80
    // Lng: Moremi (4.5190) -> X:20, Awolowo (4.5300) -> X:80

    const y = 10 - 7216 * (userLocation.lat - 7.5197);
    const x = 20 + 5454 * (userLocation.lng - 4.5190);

    return { x, y };
  }, [userLocation]);

  const handleSchematicClick = (e: React.MouseEvent<SVGSVGElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    // Only trigger if not clicking a location
    if ((e.target as Element).tagName === 'svg') {
        onMapClick(x, y);
    }
  };

  const googleMapSrc = useMemo(() => {
    // 1. Directions Mode: User Location -> Active Destination
    if (viewMode === 'google' && userLocation && activeDestination && activeDestination.lat && activeDestination.lng) {
        return `https://maps.google.com/maps?saddr=${userLocation.lat},${userLocation.lng}&daddr=${activeDestination.lat},${activeDestination.lng}&t=m&z=16&output=embed`;
    }
    // 2. User Location Mode: Centered on User
    if (viewMode === 'google' && userLocation) {
        return `https://maps.google.com/maps?q=${userLocation.lat},${userLocation.lng}&t=m&z=16&output=embed`;
    }
    // 3. Default Campus View
    return `https://maps.google.com/maps?q=Obafemi+Awolowo+University&t=k&z=15&ie=UTF8&iwloc=&output=embed`;
  }, [viewMode, userLocation, activeDestination]);

  // Dynamic sizing configuration based on expansion state
  // When expanded, the coordinate system (0-100) spans a much larger pixel area (~1000px vs ~300px).
  // We reduce the SVG units for radius/text so they stay visually similar in pixel size.
  const config = {
      radius: isExpanded ? 1.2 : 3,
      activeRadius: isExpanded ? 1.6 : 4,
      fontSize: isExpanded ? 1.2 : 3,
      textOffset: isExpanded ? 2.5 : 6,
      strokeWidth: isExpanded ? 0.5 : 1 // Visually thinner lines when zoomed
  };

  return (
    <div className={`${
        isExpanded 
          ? 'fixed inset-0 z-50 w-full h-full bg-slate-100' 
          : 'relative w-full aspect-[4/3] bg-slate-100 rounded-xl overflow-hidden border border-gray-200 shadow-inner group'
        } transition-all duration-300 ease-in-out`}
    >

      {/* View Toggle & Expand Controls */}
      <div className="absolute top-3 right-3 z-50 flex gap-2">
        <div className="flex bg-white/90 backdrop-blur rounded-lg shadow-sm border border-gray-200 p-1">
          <button 
            onClick={() => setViewMode('schematic')}
            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
              viewMode === 'schematic' 
                ? 'bg-blue-600 text-white shadow-sm' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            Schematic
          </button>
          <button 
            onClick={() => setViewMode('google')}
            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
              viewMode === 'google' 
                ? 'bg-blue-600 text-white shadow-sm' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            Google Maps
          </button>
        </div>

        <button 
          onClick={() => setIsExpanded(!isExpanded)}
          className="bg-white/90 backdrop-blur text-gray-600 hover:text-blue-600 w-8 h-8 flex items-center justify-center rounded-lg shadow-sm border border-gray-200 transition-colors"
          title={isExpanded ? "Minimize" : "Expand"}
        >
          <i className={`fas ${isExpanded ? 'fa-compress' : 'fa-expand'}`}></i>
        </button>
      </div>

      {/* Navigation Hint Overlay */}
      {viewMode === 'schematic' && activeDestination && userLocation && (
        <div className="absolute top-3 left-3 z-40 animate-in fade-in slide-in-from-left-2">
            <button 
                onClick={() => setViewMode('google')}
                className="bg-green-600 text-white px-3 py-2 rounded-lg shadow-lg text-xs font-bold flex items-center gap-2 hover:bg-green-700 transition-colors"
            >
                <i className="fas fa-directions"></i>
                Start Navigation
            </button>
        </div>
      )}

      {viewMode === 'schematic' ? (
        // SCROLL CONTAINER
        <div className={`w-full h-full ${isExpanded ? 'overflow-auto touch-pan-x touch-pan-y' : 'overflow-hidden'}`}>
            {/* CONTENT SIZER - Using vmax ensures a square canvas large enough to cover the screen for panning */}
            <div className={`relative ${isExpanded ? 'min-w-[150vmax] min-h-[150vmax]' : 'w-full h-full'}`}>

                {/* Grid Pattern */}
                <div className="absolute inset-0" style={{ 
                    backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)', 
                    backgroundSize: '20px 20px' 
                }}></div>

                <svg 
                    className="w-full h-full cursor-crosshair relative z-0"
                    onClick={handleSchematicClick}
                    viewBox="0 0 100 100"
                    // 'xMidYMid slice' ensures it covers the area without distorting aspect ratio (circles stay circles)
                    preserveAspectRatio="xMidYMid slice" 
                >
                    {/* Paths or Roads */}
                    <path d="M 50 5 L 50 95" stroke="#cbd5e1" strokeWidth={config.strokeWidth} strokeDasharray="2,2" vectorEffect="non-scaling-stroke" />
                    <path d="M 5 50 L 95 50" stroke="#cbd5e1" strokeWidth={config.strokeWidth} strokeDasharray="2,2" vectorEffect="non-scaling-stroke" />

                    {/* Animated Route Line */}
                    {userProjected && activeDestination && (
                    <path
                        d={`M ${userProjected.x} ${userProjected.y} L ${activeDestination.coords.x} ${activeDestination.coords.y}`}
                        className="stroke-blue-500 animate-dash"
                        strokeWidth={isExpanded ? 0.8 : 1.5}
                        strokeDasharray="5"
                        strokeLinecap="round"
                        fill="none"
                        vectorEffect="non-scaling-stroke"
                    />
                    )}

                    {/* User Live Location Indicator */}
                    {userProjected && (
                        <g className="transition-all duration-1000 ease-linear" style={{ transformBox: 'fill-box' }}>
                            <circle 
                                cx={userProjected.x} 
                                cy={userProjected.y} 
                                r={config.activeRadius * 1.5} 
                                className="fill-blue-500/20 animate-ping origin-center" 
                                vectorEffect="non-scaling-stroke"
                            />
                            <circle 
                                cx={userProjected.x} 
                                cy={userProjected.y} 
                                r={config.radius * 0.7} 
                                className="fill-blue-600 stroke-white stroke-[0.5px] drop-shadow-md" 
                                vectorEffect="non-scaling-stroke"
                            />
                        </g>
                    )}

                    {locations.map((loc) => {
                        const isActive = activeDestination?.id === loc.id;
                        return (
                            <g 
                                key={loc.id} 
                                onClick={(e) => { e.stopPropagation(); onLocationClick(loc); }}
                                className="cursor-pointer hover:opacity-80 transition-opacity"
                            >
                                <circle 
                                cx={loc.coords.x} 
                                cy={loc.coords.y} 
                                r={isActive ? config.activeRadius : config.radius} 
                                className={`${
                                    loc.type === 'academic' ? 'fill-blue-500' : 
                                    loc.type === 'transport' ? 'fill-yellow-500' :
                                    loc.type === 'residential' ? 'fill-purple-500' :
                                    loc.type === 'custom' ? 'fill-green-500' : 'fill-gray-500'
                                } stroke-white stroke-2 shadow-lg transition-all duration-300 ${isActive ? 'animate-pulse' : ''}`} 
                                vectorEffect="non-scaling-stroke"
                                />
                                <text 
                                x={loc.coords.x} 
                                y={loc.coords.y + config.textOffset} 
                                textAnchor="middle" 
                                fontSize={config.fontSize}
                                className={`font-bold uppercase tracking-wide select-none ${isActive ? 'fill-blue-700' : 'fill-slate-700'}`}
                                >
                                {loc.name}
                                </text>
                            </g>
                        );
                    })}
                </svg>

                <div className="absolute bottom-2 right-2 bg-white/90 backdrop-blur px-2 py-1 rounded text-[10px] text-gray-500 border border-gray-200 pointer-events-none z-10">
                    {userProjected ? "Live Location Active" : "Waiting for GPS..."}
                </div>
            </div>
        </div>
      ) : (
        <div className="w-full h-full bg-gray-200 relative">
             <iframe 
                width="100%" 
                height="100%" 
                frameBorder="0" 
                scrolling="no" 
                marginHeight={0} 
                marginWidth={0} 
                title="OAU Campus Map"
                src={googleMapSrc}
                className="w-full h-full opacity-90 hover:opacity-100 transition-opacity"
             ></iframe>

             {/* Status Badge */}
             <div className="absolute bottom-2 right-2 bg-white/90 backdrop-blur px-2 py-1 rounded text-[10px] text-blue-600 border border-blue-100 font-medium pointer-events-none flex items-center gap-1">
                {userLocation && activeDestination 
                    ? <><i className="fas fa-route"></i> Live Directions (Blue Line)</> 
                    : userLocation 
                        ? <><i className="fas fa-location-arrow"></i> Your Location</>
                        : "Satellite View"}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { CampusLocation } from '../types';

interface CampusMapProps {
  locations: CampusLocation[];
  onLocationClick: (loc: CampusLocation) => void;
  onMapClick: (x: number, y: number) => void;
  userLocation?: { lat: number; lng: number };
  activeDestination?: CampusLocation | null;
}

export const CampusMap: React.FC<CampusMapProps> = ({ 
  locations, 
  onLocationClick, 
  onMapClick,
  userLocation,
  activeDestination
}) => {
  const [viewMode, setViewMode] = useState<'schematic' | 'google'>('schematic');
  const [isExpanded, setIsExpanded] = useState(false);

  // Transform State for Pan/Zoom
  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef<{ x: number; y: number } | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const prevDestRef = useRef<string | undefined>(undefined);

  // Auto-switch to Google Maps view when destination changes via Chat
  useEffect(() => {
    if (activeDestination && activeDestination.id !== prevDestRef.current && userLocation) {
        setViewMode('google');
    }
    prevDestRef.current = activeDestination?.id;
  }, [activeDestination, userLocation]);

  // --- Map Projections ---
  const userProjected = useMemo(() => {
    if (!userLocation) return null;
    const y = 10 - 7216 * (userLocation.lat - 7.5197);
    const x = 20 + 5454 * (userLocation.lng - 4.5190);
    return { x, y };
  }, [userLocation]);

  const googleMapSrc = useMemo(() => {
    if (viewMode === 'google' && userLocation && activeDestination && activeDestination.lat && activeDestination.lng) {
        return `https://maps.google.com/maps?saddr=${userLocation.lat},${userLocation.lng}&daddr=${activeDestination.lat},${activeDestination.lng}&t=m&z=16&output=embed`;
    }
    if (viewMode === 'google' && userLocation) {
        return `https://maps.google.com/maps?q=${userLocation.lat},${userLocation.lng}&t=m&z=16&output=embed`;
    }
    return `https://maps.google.com/maps?q=Obafemi+Awolowo+University&t=k&z=15&ie=UTF8&iwloc=&output=embed`;
  }, [viewMode, userLocation, activeDestination]);


  // --- Pan & Zoom Logic ---

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const scaleSensitivity = 0.001;
    const delta = -e.deltaY * scaleSensitivity;
    const newScale = Math.min(Math.max(0.5, transform.k + delta), 8); // Min 0.5x, Max 8x

    // Zoom towards center of container for simplicity in this implementation
    setTransform(prev => ({
      ...prev,
      k: newScale
    }));
  };

  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    // Only drag left click
    if ('button' in e && e.button !== 0) return;
    setIsDragging(true);

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    dragStartRef.current = { 
      x: clientX - transform.x, 
      y: clientY - transform.y 
    };
  };

  const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !dragStartRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    setTransform(prev => ({
      ...prev,
      x: clientX - dragStartRef.current!.x,
      y: clientY - dragStartRef.current!.y
    }));
  };

  const handleMouseUp = () => {
    setIsDragging(false);
    dragStartRef.current = null;
  };

  const zoomIn = () => setTransform(prev => ({ ...prev, k: Math.min(prev.k * 1.2, 8) }));
  const zoomOut = () => setTransform(prev => ({ ...prev, k: Math.max(prev.k / 1.2, 0.5) }));
  const resetView = () => setTransform({ x: 0, y: 0, k: 1 });

  const handleSchematicClick = (e: React.MouseEvent<SVGSVGElement>) => {
    // Determine click coordinate in SVG space (0-100) taking transform into account is complex.
    // Simplified for now: allow creating landmarks only when not deeply zoomed/panned or implement inverse matrix.
    // For this user request, we prioritize the View experience.

    // We only trigger add if we weren't dragging significantly
    if (!isDragging) {
        const rect = e.currentTarget.getBoundingClientRect();
        // This math needs to account for the CSS transform on the parent div
        // However, since the SVG scales with the div, getBoundingClientRect usually represents the visual size
        // We defer precise coordinate mapping for "Add Landmark" in zoomed state for V2, 
        // passing simpler relative coords for now.
        const x = ((e.clientX - rect.left) / rect.width) * 100;
        const y = ((e.clientY - rect.top) / rect.height) * 100;
        if ((e.target as Element).tagName === 'svg') {
            onMapClick(x, y);
        }
    }
  };

  // --- Dynamic Styling for "Semantic Zoom" ---
  // As we zoom in (k increases), we shrink the radius/stroke so they stay visually constant
  const getDynamicStyle = (base: number) => base / transform.k;

  return (
    <div className={`${
        isExpanded 
          ? 'fixed inset-0 z-50 w-full h-full bg-slate-100' 
          : 'relative w-full aspect-[4/3] bg-slate-100 rounded-xl overflow-hidden border border-gray-200 shadow-inner group'
        } transition-all duration-300 ease-in-out select-none`}
    >

      {/* --- UI OVERLAYS (Fixed relative to Container) --- */}

      {/* 1. Mode Toggles & Expand */}
      <div className="absolute top-3 right-3 z-50 flex gap-2 pointer-events-auto">
        <div className="flex bg-white/90 backdrop-blur rounded-lg shadow-sm border border-gray-200 p-1">
          <button 
            onClick={() => setViewMode('schematic')}
            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
              viewMode === 'schematic' 
                ? 'bg-blue-600 text-white shadow-sm' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            Schematic
          </button>
          <button 
            onClick={() => setViewMode('google')}
            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
              viewMode === 'google' 
                ? 'bg-blue-600 text-white shadow-sm' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            Satellite
          </button>
        </div>

        <button 
          onClick={() => setIsExpanded(!isExpanded)}
          className="bg-white/90 backdrop-blur text-gray-600 hover:text-blue-600 w-8 h-8 flex items-center justify-center rounded-lg shadow-sm border border-gray-200 transition-colors"
        >
          <i className={`fas ${isExpanded ? 'fa-compress' : 'fa-expand'}`}></i>
        </button>
      </div>

      {/* 2. Zoom Controls (Only in Schematic) */}
      {viewMode === 'schematic' && (
          <div className="absolute bottom-4 right-4 z-50 flex flex-col gap-2 pointer-events-auto">
             <button onClick={zoomIn} className="w-8 h-8 bg-white rounded shadow text-gray-600 hover:text-blue-600 flex items-center justify-center text-sm font-bold active:bg-gray-100">+</button>
             <button onClick={zoomOut} className="w-8 h-8 bg-white rounded shadow text-gray-600 hover:text-blue-600 flex items-center justify-center text-sm font-bold active:bg-gray-100">-</button>
             <button onClick={resetView} className="w-8 h-8 bg-white rounded shadow text-gray-400 hover:text-gray-600 flex items-center justify-center text-xs" title="Reset View">
                 <i className="fas fa-crosshairs"></i>
             </button>
          </div>
      )}

      {/* 3. Navigation Hint */}
      {viewMode === 'schematic' && activeDestination && userLocation && (
        <div className="absolute top-3 left-3 z-40 animate-in fade-in slide-in-from-left-2 pointer-events-auto">
            <button 
                onClick={() => setViewMode('google')}
                className="bg-green-600 text-white px-3 py-2 rounded-lg shadow-lg text-xs font-bold flex items-center gap-2 hover:bg-green-700 transition-colors"
            >
                <i className="fas fa-directions"></i>
                Start Navigation
            </button>
        </div>
      )}

      {/* --- MAP CONTENT --- */}

      {viewMode === 'schematic' ? (
        <div 
            ref={containerRef}
            className="w-full h-full overflow-hidden cursor-grab active:cursor-grabbing relative touch-none bg-slate-100"
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
            onTouchStart={handleMouseDown}
            onTouchMove={handleMouseMove}
            onTouchEnd={handleMouseUp}
            onWheel={handleWheel}
        >
            {/* Transform Layer */}
            <div 
                style={{ 
                    transform: `translate(${transform.x}px, ${transform.y}px) scale(${transform.k})`,
                    transformOrigin: '0 0', // simpler math if we originate from top-left and handle offset via translate
                    width: '100%',
                    height: '100%',
                    willChange: 'transform'
                }}
            >
                {/* 
                   We use a square container for the schematic.
                   When zoomed out, it fits. When zoomed in, it expands.
                   We center it initially with flex or grid if needed, but translate handles it now.
                */}
                <div className="w-full h-full min-w-[300px] min-h-[300px] relative">

                    {/* Background Grid - Scales with map */}
                    <div className="absolute inset-0 z-0" style={{ 
                        backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)', 
                        backgroundSize: '20px 20px',
                        opacity: 0.5
                    }}></div>

                    <svg 
                        className="w-full h-full overflow-visible"
                        viewBox="0 0 100 100"
                        preserveAspectRatio="xMidYMid meet"
                        onClick={handleSchematicClick}
                    >
                        {/* Reference Roads */}
                        <path d="M 50 5 L 50 95" stroke="#cbd5e1" strokeWidth={getDynamicStyle(1)} strokeDasharray={`${getDynamicStyle(2)},${getDynamicStyle(2)}`} vectorEffect="non-scaling-stroke" />
                        <path d="M 5 50 L 95 50" stroke="#cbd5e1" strokeWidth={getDynamicStyle(1)} strokeDasharray={`${getDynamicStyle(2)},${getDynamicStyle(2)}`} vectorEffect="non-scaling-stroke" />

                        {/* Animated Route Line */}
                        {userProjected && activeDestination && (
                        <path
                            d={`M ${userProjected.x} ${userProjected.y} L ${activeDestination.coords.x} ${activeDestination.coords.y}`}
                            className="stroke-blue-500 animate-dash"
                            strokeWidth={getDynamicStyle(1.5)}
                            strokeDasharray={getDynamicStyle(5)}
                            strokeLinecap="round"
                            fill="none"
                            vectorEffect="non-scaling-stroke"
                        />
                        )}

                        {/* User Location */}
                        {userProjected && (
                            <g>
                                <circle 
                                    cx={userProjected.x} 
                                    cy={userProjected.y} 
                                    r={getDynamicStyle(6)} 
                                    className="fill-blue-500/20 animate-ping origin-center" 
                                />
                                <circle 
                                    cx={userProjected.x} 
                                    cy={userProjected.y} 
                                    r={getDynamicStyle(2)} 
                                    className="fill-blue-600 stroke-white drop-shadow-md"
                                    strokeWidth={getDynamicStyle(0.5)}
                                />
                            </g>
                        )}

                        {/* Locations */}
                        {locations.map((loc) => {
                            const isActive = activeDestination?.id === loc.id;

                            // Visual Constants (In SVG Units)
                            // We divide by K so that as K goes up (zoom in), the radius in SVG units goes down
                            // Resulting in a constant pixel size on screen.
                            const baseRadius = isActive ? 5 : 3; 
                            const radius = getDynamicStyle(baseRadius);
                            const fontSize = getDynamicStyle(3);
                            const textOffset = getDynamicStyle(isActive ? 7 : 5);
                            const strokeW = getDynamicStyle(0.8);

                            return (
                                <g 
                                    key={loc.id} 
                                    onClick={(e) => { e.stopPropagation(); onLocationClick(loc); }}
                                    className="cursor-pointer hover:opacity-80 transition-opacity"
                                >
                                    <circle 
                                        cx={loc.coords.x} 
                                        cy={loc.coords.y} 
                                        r={radius} 
                                        strokeWidth={strokeW}
                                        className={`${
                                            loc.type === 'academic' ? 'fill-blue-500' : 
                                            loc.type === 'transport' ? 'fill-yellow-500' :
                                            loc.type === 'residential' ? 'fill-purple-500' :
                                            loc.type === 'custom' ? 'fill-green-500' : 'fill-gray-500'
                                        } stroke-white shadow-lg transition-colors duration-300 ${isActive ? 'animate-pulse' : ''}`} 
                                    />
                                    <text 
                                        x={loc.coords.x} 
                                        y={loc.coords.y + textOffset} 
                                        textAnchor="middle" 
                                        fontSize={fontSize}
                                        className={`font-bold uppercase tracking-wide select-none pointer-events-none ${isActive ? 'fill-blue-700' : 'fill-slate-700'}`}
                                        style={{ textShadow: `0px 0px ${getDynamicStyle(2)}px white` }} // Readable halo
                                    >
                                        {loc.name}
                                    </text>
                                </g>
                            );
                        })}
                    </svg>
                </div>
            </div>

            <div className="absolute bottom-4 left-4 pointer-events-none">
                 <div className="bg-white/90 backdrop-blur px-2 py-1 rounded text-[10px] text-gray-500 border border-gray-200">
                    {transform.k.toFixed(1)}x Zoom
                </div>
            </div>

        </div>
      ) : (
        <div className="w-full h-full bg-gray-200 relative">
             <iframe 
                width="100%" 
                height="100%" 
                frameBorder="0" 
                scrolling="no" 
