  const [viewMode, setViewMode] = useState<'schematic' | 'google'>('schematic');
  const [isExpanded, setIsExpanded] = useState(false);

  // Transform State for Pan/Zoom
  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef<{ x: number; y: number } | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const prevDestRef = useRef<string | undefined>(undefined);

  // Auto-switch to Google Maps view when destination changes via Chat
  useEffect(() => {
    if (activeDestination && activeDestination.id !== prevDestRef.current && userLocation) {
        setViewMode('google');
    }
    prevDestRef.current = activeDestination?.id;
  }, [activeDestination, userLocation]);

  // --- Map Projections ---
  const userProjected = useMemo(() => {
    if (!userLocation) return null;
    const y = 10 - 7216 * (userLocation.lat - 7.5197);
    const x = 20 + 5454 * (userLocation.lng - 4.5190);
    return { x, y };
  }, [userLocation]);

  const googleMapSrc = useMemo(() => {
    if (viewMode === 'google' && userLocation && activeDestination && activeDestination.lat && activeDestination.lng) {
        return `https://maps.google.com/maps?saddr=${userLocation.lat},${userLocation.lng}&daddr=${activeDestination.lat},${activeDestination.lng}&t=m&z=16&output=embed`;
    }
    if (viewMode === 'google' && userLocation) {
        return `https://maps.google.com/maps?q=${userLocation.lat},${userLocation.lng}&t=m&z=16&output=embed`;
    }
    return `https://maps.google.com/maps?q=Obafemi+Awolowo+University&t=k&z=15&ie=UTF8&iwloc=&output=embed`;
  }, [viewMode, userLocation, activeDestination]);


  // --- Pan & Zoom Logic ---

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const scaleSensitivity = 0.001;
    const delta = -e.deltaY * scaleSensitivity;
    const newScale = Math.min(Math.max(0.5, transform.k + delta), 8); // Min 0.5x, Max 8x

    // Zoom towards center of container for simplicity in this implementation
    setTransform(prev => ({
      ...prev,
      k: newScale
    }));
  };

  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    // Only drag left click
    if ('button' in e && e.button !== 0) return;
    setIsDragging(true);

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    dragStartRef.current = { 
      x: clientX - transform.x, 
      y: clientY - transform.y 
    };
  };

  const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !dragStartRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    // Capture values synchronously to avoid Ref mutation race conditions
    // where dragStartRef.current becomes null before the setTransform callback executes
    const startX = dragStartRef.current.x;
    const startY = dragStartRef.current.y;

    setTransform(prev => ({
      ...prev,
      x: clientX - startX,
      y: clientY - startY
    }));
  };

