    // Simplified for now: allow creating landmarks only when not deeply zoomed/panned or implement inverse matrix.
    // For this user request, we prioritize the View experience.

    // We only trigger add if we weren't dragging significantly
    if (!isDragging) {
        const rect = e.currentTarget.getBoundingClientRect();
        // This math needs to account for the CSS transform on the parent div
        // However, since the SVG scales with the div, getBoundingClientRect usually represents the visual size
        // We defer precise coordinate mapping for "Add Landmark" in zoomed state for V2, 
        // passing simpler relative coords for now.
        const x = ((e.clientX - rect.left) / rect.width) * 100;
        const y = ((e.clientY - rect.top) / rect.height) * 100;
        if ((e.target as Element).tagName === 'svg') {
            onMapClick(x, y);
        }
    }
  };

