            }`}
          >
            Schematic
          </button>
          <button 
            onClick={() => setViewMode('google')}
            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
              viewMode === 'google' 
                ? 'bg-blue-600 text-white shadow-sm' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            Satellite
          </button>
        </div>

        <button 
          onClick={() => setIsExpanded(!isExpanded)}
          className="bg-white/90 backdrop-blur text-gray-600 hover:text-blue-600 w-8 h-8 flex items-center justify-center rounded-lg shadow-sm border border-gray-200 transition-colors"
        >
          <i className={`fas ${isExpanded ? 'fa-compress' : 'fa-expand'}`}></i>
        </button>
      </div>

      {viewMode === 'schematic' && (
          <div className="absolute bottom-4 right-4 z-50 flex flex-col gap-4 pointer-events-auto items-end">
             <div className="flex flex-col items-end gap-2">
                 {showAddMenu && (
                    <div className="flex flex-col gap-2 animate-in slide-in-from-bottom-2 fade-in duration-200 origin-bottom-right mb-1">
                         <button 
                            onClick={handleAddCurrentLocation}
                            disabled={!userProjected}
                            className="bg-blue-600 text-white px-3 py-1.5 rounded-lg shadow-lg text-xs font-bold flex items-center gap-2 hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed whitespace-nowrap"
                         >
                            <span>My Location</span>
                            <i className="fas fa-location-dot"></i>
                         </button>
                         <div className="bg-white text-gray-600 px-3 py-1.5 rounded-lg shadow-lg text-xs font-bold flex items-center gap-2 whitespace-nowrap border border-gray-100">
                            <span>Tap map to pick</span>
                            <i className="fas fa-hand-pointer"></i>
                         </div>
                    </div>
                 )}
                 <button 
                    onClick={() => setShowAddMenu(!showAddMenu)}
                    className={`w-12 h-12 rounded-full shadow-lg flex items-center justify-center transition-all duration-300 ${
                        showAddMenu ? 'bg-red-500 text-white rotate-45' : 'bg-blue-600 text-white hover:bg-blue-700'
                    }`}
                    title="Add Location"
                 >
                    <i className="fas fa-plus text-xl"></i>
                 </button>
             </div>

             <div className="flex flex-col gap-1 bg-white/90 backdrop-blur rounded-lg shadow-sm border border-gray-200 p-1">
                 <button onClick={zoomIn} className="w-8 h-8 rounded hover:bg-gray-100 text-gray-600 font-bold active:bg-gray-200 transition-colors">+</button>
                 <button onClick={zoomOut} className="w-8 h-8 rounded hover:bg-gray-100 text-gray-600 font-bold active:bg-gray-200 transition-colors">-</button>
                 <div className="h-px bg-gray-200 my-0.5"></div>
                 <button onClick={resetView} className="w-8 h-8 rounded hover:bg-gray-100 text-gray-500 text-xs active:bg-gray-200 transition-colors" title="Reset View">
                     <i className="fas fa-compress-arrows-alt"></i>
                 </button>
             </div>
          </div>
      )}

      {viewMode === 'schematic' && activeDestination && userLocation && (
        <div className="absolute top-3 left-3 z-40 animate-in fade-in slide-in-from-left-2 pointer-events-auto">
            <button 
                onClick={() => setViewMode('google')}
                className="bg-green-600 text-white px-3 py-2 rounded-lg shadow-lg text-xs font-bold flex items-center gap-2 hover:bg-green-700 transition-colors"
            >
                <i className="fas fa-directions"></i>
                Start Navigation
            </button>
        </div>
