            onPress={() => setViewMode('schematic')}
            className={`px-3 py-2 rounded-md ${viewMode === 'schematic' ? 'bg-blue-600' : 'bg-transparent'}`}
          >
            <Text className={`text-xs font-bold ${viewMode === 'schematic' ? 'text-white' : 'text-gray-600'}`}>Map</Text>
          </TouchableOpacity>
          <TouchableOpacity 
            onPress={() => setViewMode('google')}
            className={`px-3 py-2 rounded-md ${viewMode === 'google' ? 'bg-blue-600' : 'bg-transparent'}`}
          >
            <Text className={`text-xs font-bold ${viewMode === 'google' ? 'text-white' : 'text-gray-600'}`}>Sat</Text>
          </TouchableOpacity>
      </View>

      {/* Map Content */}
      {viewMode === 'schematic' ? (
        <View className="flex-1 justify-center items-center bg-blue-50">
            <View style={{ width: mapSize, height: mapSize, backgroundColor: '#e2e8f0' }}>
                <Svg height="100%" width="100%" viewBox="0 0 100 100">
                    {/* Background Grid */}
                    <Rect x="0" y="0" width="100" height="100" fill="#f1f5f9" />

                    {/* Roads */}
                    <Path d="M 50 5 L 50 95" stroke="#cbd5e1" strokeWidth="1" strokeDasharray="2,2" />
                    <Path d="M 5 50 L 95 50" stroke="#cbd5e1" strokeWidth="1" strokeDasharray="2,2" />

                    {/* Route Line */}
                    {userProjected && activeDestination && (
                        <Path
                            d={`M ${userProjected.x} ${userProjected.y} L ${activeDestination.coords.x} ${activeDestination.coords.y}`}
                            stroke="#3b82f6"
                            strokeWidth="1.5"
                            strokeDasharray="4"
                            fill="none"
                        />
                    )}

                    {/* User Location */}
                    {userProjected && (
                        <Circle 
                            cx={userProjected.x} 
                            cy={userProjected.y} 
                            r="3" 
                            fill="#2563eb" 
                            stroke="white" 
                            strokeWidth="1" 
                        />
                    )}

                    {/* Locations */}
                    {locations.map((loc) => {
                        const isActive = activeDestination?.id === loc.id;
                        return (
                            <G 
                                key={loc.id} 
                                onPress={() => onLocationClick(loc)}
                            >
                                <Circle 
                                    cx={loc.coords.x} 
                                    cy={loc.coords.y} 
                                    r={isActive ? "5" : "3"} 
                                    fill={loc.type === 'academic' ? '#3b82f6' : '#eab308'}
                                    stroke="white"
                                    strokeWidth="0.5"
                                />
