import React from 'react';
import { View, Text, TouchableOpacity, Linking } from 'react-native';
import { Message } from '../types';

interface ChatMessageProps {
  message: Message;
}

export const ChatMessage: React.FC<ChatMessageProps> = ({ message }) => {
  const isBot = message.role === 'bot';

  // Helper to render text with bold formatting
  const renderContent = () => {
    // Basic bold parsing for **text**
    const parts = message.content.split(/(\*\*.*?\*\*)/g);
    return (
        <Text className={`text-base leading-6 ${isBot ? 'text-gray-800' : 'text-white'}`}>
            {parts.map((part, index) => {
                if (part.startsWith('**') && part.endsWith('**')) {
                    return <Text key={index} className="font-bold">{part.slice(2, -2)}</Text>;
                }
                return part;
            })}
        </Text>
    );
  };

  return (
    <View className={`w-full mb-4 flex-row ${isBot ? 'justify-start' : 'justify-end'}`}>
      <View className={`max-w-[85%] ${isBot ? 'items-start' : 'items-end'}`}>

        {/* Message Bubble */}
        <View className={`px-4 py-3 rounded-2xl shadow-sm ${
          isBot 
            ? 'bg-white border border-gray-200 rounded-bl-none' 
            : 'bg-blue-600 rounded-br-none'
        }`}>
          {renderContent()}
        </View>

        {/* Grounding Info (Maps/Search) */}
        {isBot && message.groundingMetadata && (
             <View className="mt-2 flex-row flex-wrap gap-2">
                 {message.groundingMetadata.groundingChunks?.map((chunk: any, idx: number) => {
                     if (chunk.web?.uri) {
                         return (
                             <TouchableOpacity 
                                key={idx} 
                                onPress={() => Linking.openURL(chunk.web.uri)}
                                className="bg-white border border-gray-200 px-2 py-1 rounded-full"
                             >
                                 <Text className="text-blue-600 text-xs">{chunk.web.title || 'Source'}</Text>
                             </TouchableOpacity>
                         );
                     }
                     return null;
                 })}
             </View>
        )}
      </View>
    </View>
  );
};

import { GoogleGenAI, Modality } from "@google/genai";

const apiKey = process.env.API_KEY;
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

interface GeminiRequestOptions {
  modelType: 'fast' | 'balanced' | 'thinking' | 'maps' | 'search';
  systemInstruction?: string;
  location?: { lat: number; lng: number }; 
}

export interface GeminiResponse {
  text: string;
  groundingMetadata?: any; 
}

export const generateGeminiResponse = async (
  prompt: string,
  options: GeminiRequestOptions
): Promise<GeminiResponse> => {
  if (!ai) throw new Error("API Key missing");

  let model = 'gemini-3-flash-preview'; 
  let config: any = {
    systemInstruction: options.systemInstruction,
  };

  switch (options.modelType) {
    case 'fast':
      model = 'gemini-2.0-flash-lite-preview-02-05';
      break;
    case 'thinking':
      model = 'gemini-3-pro-preview';
      config.thinkingConfig = { thinkingBudget: 16000 };
      break;
    case 'maps':
      model = 'gemini-2.5-flash';
      config.tools = [{ googleMaps: {} }];
      break;
    case 'search':
      model = 'gemini-3-flash-preview';
      config.tools = [{ googleSearch: {} }];
      break;
    default:
      model = 'gemini-3-flash-preview'; 
      break;
  }

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config
    });

    return {
      text: response.text || "No response generated.",
      groundingMetadata: response.candidates?.[0]?.groundingMetadata
    };
  } catch (error) {
    console.error(`Gemini ${options.modelType} Error:`, error);
    return { text: "I encountered an error connecting to the campus network." };
  }
};

