// Helper for Async Storage
const useAsyncStorage = <T,>(key: string, initialValue: T): [T, React.Dispatch<React.SetStateAction<T>>] => {
  const [value, setValue] = useState<T>(initialValue);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const item = await AsyncStorage.getItem(key);
        if (item) setValue(JSON.parse(item));
      } catch (e) {
        console.error('Failed to load ' + key);
      } finally {
        setLoaded(true);
      }
    })();
  }, [key]);

  useEffect(() => {
    if (loaded) {
      AsyncStorage.setItem(key, JSON.stringify(value)).catch(e => console.error(e));
    }
  }, [key, value, loaded]);

  return [value, setValue];
};

const App: React.FC = () => {
  const [messages, setMessages] = useAsyncStorage<Message[]>('uninav_history_v2', [
    {
      id: '1',
      role: 'bot',
      content: "Welcome to OAU! I can help you find the Senate Building, Moremi Hall, or check the latest news.",
      timestamp: Date.now()
    }
  ]);

  const [locations, setLocations] = useAsyncStorage<CampusLocation[]>('uninav_locations_v2', CAMPUS_DATA.locations);

  const [isLoading, setIsLoading] = useState(false);
  const [activeDestination, setActiveDestination] = useState<CampusLocation | null>(null);
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | undefined>(undefined);

  // Mobile UI State
  const [activeTab, setActiveTab] = useState<'chat' | 'map'>('chat');
  const [isLiveOpen, setIsLiveOpen] = useState(false);

  const scrollViewRef = useRef<ScrollView>(null);

  useEffect(() => {
    setTimeout(() => scrollViewRef.current?.scrollToEnd({ animated: true }), 100);
  }, [messages, activeTab]);

  // Mock Geolocation for Demo (Real impl requires expo-location)
  useEffect(() => {
    setUserLocation({ lat: 7.5197, lng: 4.5190 }); 
  }, []);

  const processUserRequest = async (text: string) => {
    const userMsg: Message = {
      id: uuidv4(),
      role: 'user',
      content: text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      const { answer, context, groundingMetadata, suggestedLocationId } = await processQuery(text, locations, userLocation);

      if (suggestedLocationId) {
          const loc = locations.find(l => l.id === suggestedLocationId);
          if (loc) {
              setActiveDestination(loc);
              setActiveTab('map'); // Switch to map to show location
          }
      }

      const botMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: answer,
        timestamp: Date.now(),
        retrievedContext: context,
        groundingMetadata
      };

      setMessages(prev => [...prev, botMsg]);

    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: "System Error: Unable to process request.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLocationClick = (loc: CampusLocation) => {
    setActiveDestination(loc);
    setActiveTab('chat');
    processUserRequest(`Tell me about ${loc.name} and how to get there.`);
  };

  const clearHistory = () => {
    Alert.alert("Clear History", "Are you sure?", [
        { text: "Cancel" },
        { text: "OK", onPress: () => setMessages([]) }
    ]);
  };

  const handleLiveTranscript = (role: 'user' | 'bot', text: string) => {
    // Add live transcripts to chat history
    const msg: Message = {
      id: uuidv4(),
      role,
      content: text,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, msg]);
  };

  return (
    <SafeAreaView className="flex-1 bg-gray-50">
      <StatusBar barStyle="dark-content" />

      {/* Header */}
      <View className="h-14 bg-blue-600 flex-row justify-between items-center px-4 shadow-sm z-10">
          <View className="flex-row items-center gap-2">
             <Text className="text-white font-bold text-lg">OAU UniNav</Text>
          </View>
          <View className="flex-row gap-4">
             <TouchableOpacity onPress={clearHistory}>
                <Text className="text-blue-100 text-xs">Clear</Text>
             </TouchableOpacity>
          </View>
      </View>

      {/* Main Content Area */}
      <View className="flex-1">
        {activeTab === 'map' ? (
            <View className="flex-1">
                <CampusMap 
                    locations={locations} 
                    onLocationClick={handleLocationClick}
                    onMapClick={() => {}}
                    userLocation={userLocation}
                    activeDestination={activeDestination}
                />
            </View>
        ) : (
            <KeyboardAvoidingView 
                behavior={Platform.OS === "ios" ? "padding" : "height"} 
                className="flex-1 flex-col"
            >
                <ScrollView 
                    ref={scrollViewRef}
                    className="flex-1 px-4 py-2"
                    contentContainerStyle={{ paddingBottom: 20 }}
                >
                    {messages.map(msg => (
                        <ChatMessage key={msg.id} message={msg} />
                    ))}
                    {isLoading && (
                        <View className="bg-white p-3 rounded-lg self-start border border-gray-200 mb-4">
                             <Text className="text-gray-400 text-xs">Thinking...</Text>
                        </View>
                    )}
                </ScrollView>
                <InputArea 
                    onSend={processUserRequest} 
                    onStartLive={() => setIsLiveOpen(true)}
                    isLoading={isLoading} 
                    voiceMode={true}
                />
            </KeyboardAvoidingView>
        )}
      </View>

      {/* Live API Modal */}
      <LiveAPI 
        visible={isLiveOpen} 
        onClose={() => setIsLiveOpen(false)}
        onTranscript={handleLiveTranscript}
      />

      {/* Bottom Tab Bar */}
      <View className="flex-row bg-white border-t border-gray-200 h-16 pb-2">
          <TouchableOpacity 
            onPress={() => setActiveTab('chat')} 
            className="flex-1 justify-center"
          >
             <Text 
                className={`text-center py-2 font-bold ${activeTab === 'chat' ? 'text-blue-600' : 'text-gray-400'}`}
            >
                Chat
             </Text>
          </TouchableOpacity>
          <TouchableOpacity 
            onPress={() => setActiveTab('map')} 
            className="flex-1 justify-center"
          >
             <Text 
                className={`text-center py-2 font-bold ${activeTab === 'map' ? 'text-blue-600' : 'text-gray-400'}`}
             >
                Campus Map
             </Text>
          </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
};

