import { CampusMap } from './components/CampusMap';
import { LiveAPI } from './components/LiveAPI';
import { CAMPUS_DATA } from './data/campusData';

// Helper for Async Storage
const useAsyncStorage = <T,>(key: string, initialValue: T): [T, React.Dispatch<React.SetStateAction<T>>] => {
  const [value, setValue] = useState<T>(initialValue);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const item = await AsyncStorage.getItem(key);
        if (item) setValue(JSON.parse(item));
      } catch (e) {
        console.error('Failed to load ' + key);
      } finally {
        setLoaded(true);
      }
    })();
  }, [key]);

  useEffect(() => {
    if (loaded) {
      AsyncStorage.setItem(key, JSON.stringify(value)).catch(e => console.error(e));
    }
  }, [key, value, loaded]);

  return [value, setValue];
};

const App: React.FC = () => {
  const [messages, setMessages] = useAsyncStorage<Message[]>('uninav_history_v2', [
    {
      id: '1',
      role: 'bot',
      content: "Welcome to OAU! I can help you find the Senate Building, Moremi Hall, or check the latest news.",
      timestamp: Date.now()
    }
  ]);

  const [locations, setLocations] = useAsyncStorage<CampusLocation[]>('uninav_locations_v2', CAMPUS_DATA.locations);

  const [isLoading, setIsLoading] = useState(false);
  const [activeDestination, setActiveDestination] = useState<CampusLocation | null>(null);
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | undefined>(undefined);

  // Mobile UI State
  const [activeTab, setActiveTab] = useState<'chat' | 'map'>('chat');
  const [isLiveOpen, setIsLiveOpen] = useState(false);

  const scrollViewRef = useRef<ScrollView>(null);

  useEffect(() => {
    setTimeout(() => scrollViewRef.current?.scrollToEnd({ animated: true }), 100);
  }, [messages, activeTab]);

  // Mock Geolocation for Demo (Real impl requires expo-location)
  useEffect(() => {
    setUserLocation({ lat: 7.5197, lng: 4.5190 }); 
  }, []);

  const processUserRequest = async (text: string) => {
    const userMsg: Message = {
      id: uuidv4(),
      role: 'user',
      content: text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      const { answer, context, groundingMetadata, suggestedLocationId } = await processQuery(text, locations, userLocation);

      if (suggestedLocationId) {
          const loc = locations.find(l => l.id === suggestedLocationId);
          if (loc) {
              setActiveDestination(loc);
              setActiveTab('map'); // Switch to map to show location
          }
      }

      const botMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: answer,
        timestamp: Date.now(),
        retrievedContext: context,
        groundingMetadata
      };

      setMessages(prev => [...prev, botMsg]);

    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: uuidv4(),
        role: 'bot',
        content: "System Error: Unable to process request.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLocationClick = (loc: CampusLocation) => {
    setActiveDestination(loc);
    setActiveTab('chat');
    processUserRequest(`Tell me about ${loc.name} and how to get there.`);
  };

  const clearHistory = () => {
    Alert.alert("Clear History", "Are you sure?", [
        { text: "Cancel" },
        { text: "OK", onPress: () => setMessages([]) }
    ]);
  };

  const handleLiveTranscript = (role: 'user' | 'bot', text: string) => {
    // Add live transcripts to chat history
    const msg: Message = {
      id: uuidv4(),
      role,
      content: text,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, msg]);
  };

  return (
    <SafeAreaView style={{ flex: 1, backgroundColor: '#f9fafb' }}>
      <StatusBar barStyle="dark-content" />

      {/* Header */}
      <View style={{ height: 56, backgroundColor: '#2563eb', flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', paddingHorizontal: 16, shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.2, shadowRadius: 1.41, elevation: 2, zIndex: 10 }}>
          <View style={{ flexDirection: 'row', alignItems: 'center', gap: 8 }}>
             <Text style={{ color: 'white', fontWeight: 'bold', fontSize: 18 }}>OAU UniNav</Text>
          </View>
          <View style={{ flexDirection: 'row', gap: 16 }}>
             <TouchableOpacity onPress={clearHistory}>
                <Text style={{ color: '#dbeafe', fontSize: 12 }}>Clear</Text>
             </TouchableOpacity>
          </View>
      </View>

      {/* Main Content Area */}
      <View style={{ flex: 1 }}>
        {activeTab === 'map' ? (
            <View style={{ flex: 1 }}>
                <CampusMap 
                    locations={locations} 
                    onLocationClick={handleLocationClick}
                    onMapClick={() => {}}
                    userLocation={userLocation}
                    activeDestination={activeDestination}
                />
            </View>
        ) : (
            <KeyboardAvoidingView 
                behavior={Platform.OS === "ios" ? "padding" : "height"} 
                style={{ flex: 1, flexDirection: 'column' }}
            >
                <ScrollView 
                    ref={scrollViewRef}
                    style={{ flex: 1, paddingHorizontal: 16, paddingVertical: 8 }}
                    contentContainerStyle={{ paddingBottom: 20 }}
                >
                    {messages.map(msg => (
                        <ChatMessage key={msg.id} message={msg} />
                    ))}
                    {isLoading && (
                        <View style={{ backgroundColor: 'white', padding: 12, borderRadius: 8, alignSelf: 'flex-start', borderWidth: 1, borderColor: '#e5e7eb', marginBottom: 16 }}>
                             <Text style={{ color: '#9ca3af', fontSize: 12 }}>Thinking...</Text>
                        </View>
                    )}
                </ScrollView>
                <InputArea 
                    onSend={processUserRequest} 
                    onStartLive={() => setIsLiveOpen(true)}
                    isLoading={isLoading} 
                    voiceMode={true}
                />
            </KeyboardAvoidingView>
        )}
      </View>

      {/* Live API Modal */}
      <LiveAPI 
        visible={isLiveOpen} 
        onClose={() => setIsLiveOpen(false)}
        onTranscript={handleLiveTranscript}
      />

      {/* Bottom Tab Bar */}
      <View style={{ flexDirection: 'row', backgroundColor: 'white', borderTopWidth: 1, borderTopColor: '#e5e7eb', height: 64, paddingBottom: 8 }}>
          <TouchableOpacity 
            onPress={() => setActiveTab('chat')} 
            style={{ flex: 1, justifyContent: 'center' }}
          >
             <Text 
                style={{ textAlign: 'center', paddingVertical: 8, fontWeight: 'bold', color: activeTab === 'chat' ? '#2563eb' : '#9ca3af' }}
            >
                Chat
             </Text>
          </TouchableOpacity>
          <TouchableOpacity 
            onPress={() => setActiveTab('map')} 
            style={{ flex: 1, justifyContent: 'center' }}
          >
             <Text 
                style={{ textAlign: 'center', paddingVertical: 8, fontWeight: 'bold', color: activeTab === 'map' ? '#2563eb' : '#9ca3af' }}
             >
                Campus Map
             </Text>
          </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { View, Text, TouchableOpacity, Dimensions } from 'react-native';
import { Svg, Circle, Path, G, Text as SvgText, Rect } from 'react-native-svg';
import { WebView } from 'react-native-webview';
import { CampusLocation } from '../types';

interface CampusMapProps {
  locations: CampusLocation[];
  onLocationClick: (loc: CampusLocation) => void;
  onMapClick: (x: number, y: number) => void;
  userLocation?: { lat: number; lng: number };
  activeDestination?: CampusLocation | null;
}

export const CampusMap: React.FC<CampusMapProps> = ({ 
  locations, 
  onLocationClick, 
  userLocation,
  activeDestination
}) => {
  const [viewMode, setViewMode] = useState<'schematic' | 'google'>('schematic');

  // Basic transforms (Static for this simple conversion, real pan/zoom requires Reanimated/GestureHandler)
  const screenWidth = Dimensions.get('window').width;
  const mapSize = screenWidth; 

  // Auto-switch
  useEffect(() => {
    if (activeDestination && userLocation) {
        // Keep in schematic to show route, user can toggle
    }
  }, [activeDestination, userLocation]);

  const userProjected = useMemo(() => {
    if (!userLocation) return null;
    const y = 10 - 7216 * (userLocation.lat - 7.5197);
    const x = 20 + 5454 * (userLocation.lng - 4.5190);
    return { x, y };
  }, [userLocation]);

  const googleMapSrc = useMemo(() => {
    const baseUrl = "https://maps.google.com/maps";
    if (viewMode === 'google' && userLocation && activeDestination) {
        return `${baseUrl}?saddr=${userLocation.lat},${userLocation.lng}&daddr=${activeDestination.lat},${activeDestination.lng}&t=m&z=16&output=embed`;
    }
    return `${baseUrl}?q=Obafemi+Awolowo+University&t=k&z=15&ie=UTF8&iwloc=&output=embed`;
  }, [viewMode, userLocation, activeDestination]);

  return (
    <View style={{ flex: 1, backgroundColor: '#f3f4f6', position: 'relative' }}>

      {/* Toggle Controls */}
      <View style={{ position: 'absolute', top: 16, right: 16, zIndex: 50, flexDirection: 'row', backgroundColor: 'white', borderRadius: 8, padding: 4, borderWidth: 1, borderColor: '#e5e7eb', shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.1, shadowRadius: 2, elevation: 2 }}>
          <TouchableOpacity 
            onPress={() => setViewMode('schematic')}
            style={{ paddingHorizontal: 12, paddingVertical: 8, borderRadius: 6, backgroundColor: viewMode === 'schematic' ? '#2563eb' : 'transparent' }}
          >
            <Text style={{ fontSize: 12, fontWeight: 'bold', color: viewMode === 'schematic' ? 'white' : '#4b5563' }}>Map</Text>
          </TouchableOpacity>
          <TouchableOpacity 
            onPress={() => setViewMode('google')}
            style={{ paddingHorizontal: 12, paddingVertical: 8, borderRadius: 6, backgroundColor: viewMode === 'google' ? '#2563eb' : 'transparent' }}
          >
            <Text style={{ fontSize: 12, fontWeight: 'bold', color: viewMode === 'google' ? 'white' : '#4b5563' }}>Sat</Text>
          </TouchableOpacity>
      </View>

      {/* Map Content */}
      {viewMode === 'schematic' ? (
        <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: '#eff6ff' }}>
            <View style={{ width: mapSize, height: mapSize, backgroundColor: '#e2e8f0' }}>
                <Svg height="100%" width="100%" viewBox="0 0 100 100">
                    {/* Background Grid */}
                    <Rect x="0" y="0" width="100" height="100" fill="#f1f5f9" />

                    {/* Roads */}
                    <Path d="M 50 5 L 50 95" stroke="#cbd5e1" strokeWidth="1" strokeDasharray="2,2" />
                    <Path d="M 5 50 L 95 50" stroke="#cbd5e1" strokeWidth="1" strokeDasharray="2,2" />

                    {/* Route Line */}
                    {userProjected && activeDestination && (
                        <Path
                            d={`M ${userProjected.x} ${userProjected.y} L ${activeDestination.coords.x} ${activeDestination.coords.y}`}
                            stroke="#3b82f6"
                            strokeWidth="1.5"
                            strokeDasharray="4"
                            fill="none"
                        />
                    )}

                    {/* User Location */}
                    {userProjected && (
                        <Circle 
                            cx={userProjected.x} 
                            cy={userProjected.y} 
                            r="3" 
                            fill="#2563eb" 
                            stroke="white" 
                            strokeWidth="1" 
                        />
                    )}

                    {/* Locations */}
                    {locations.map((loc) => {
                        const isActive = activeDestination?.id === loc.id;
                        return (
                            <G 
                                key={loc.id} 
                                onPress={() => onLocationClick(loc)}
                            >
                                <Circle 
                                    cx={loc.coords.x} 
                                    cy={loc.coords.y} 
                                    r={isActive ? "5" : "3"} 
                                    fill={loc.type === 'academic' ? '#3b82f6' : '#eab308'}
                                    stroke="white"
                                    strokeWidth="0.5"
                                />
                                <SvgText
                                    x={loc.coords.x}
                                    y={loc.coords.y + (isActive ? 7 : 5)}
                                    fill={isActive ? "#1d4ed8" : "#334155"}
                                    fontSize={isActive ? "4" : "3"}
                                    fontWeight="bold"
                                    textAnchor="middle"
                                >
                                    {loc.name}
                                </SvgText>
                            </G>
                        );
                    })}
                </Svg>
            </View>
            <View style={{ position: 'absolute', bottom: 16, left: 16, backgroundColor: 'rgba(255,255,255,0.8)', padding: 8, borderRadius: 8 }}>
                <Text style={{ fontSize: 12, color: '#6b7280' }}>Tap icons to interact</Text>
            </View>
        </View>
      ) : (
        <WebView 
            source={{ uri: googleMapSrc }}
            style={{ flex: 1 }}
        />
      )}
    </View>
  );
};

import React, { useEffect, useState } from 'react';
import { View, Text, TouchableOpacity, Modal, ActivityIndicator, Alert } from 'react-native';
// import { GoogleGenAI } from '@google/genai'; // Keeping logic but commenting out actual socket connection for stability in this demo

interface LiveAPIProps {
  visible: boolean;
  onClose: () => void;
  onTranscript: (role: 'user' | 'bot', text: string) => void;
}

export const LiveAPI: React.FC<LiveAPIProps> = ({ visible, onClose, onTranscript }) => {
  const [status, setStatus] = useState<'connecting' | 'connected' | 'error'>('connecting');
  const [volume, setVolume] = useState(0);

  // Simulation of connection for the UI demo
  useEffect(() => {
    if (visible) {
      setStatus('connecting');
      const timer = setTimeout(() => {
        setStatus('connected');
        // Simulate volume pulsing
        const volInterval = setInterval(() => {
            setVolume(Math.random());
        }, 200);
        return () => clearInterval(volInterval);
      }, 1500);

      return () => clearTimeout(timer);
    }
  }, [visible]);

  const handleClose = () => {
    onClose();
    setStatus('connecting');
  };

  return (
    <Modal
      animationType="slide"
      transparent={true}
      visible={visible}
      onRequestClose={handleClose}
    >
      <View style={{ flex: 1, backgroundColor: 'rgba(0,0,0,0.9)', justifyContent: 'center', alignItems: 'center', position: 'relative' }}>
         {/* Close Button */}
         <TouchableOpacity 
            onPress={handleClose} 
            style={{ position: 'absolute', top: 48, right: 24, padding: 16, zIndex: 10 }}
         >
           <Text style={{ color: 'rgba(255,255,255,0.6)', fontSize: 18, fontWeight: 'bold' }}>X</Text>
         </TouchableOpacity>

         <View style={{ alignItems: 'center', gap: 32, width: '100%', paddingHorizontal: 32 }}>
            {/* Visualizer Circle */}
            <View 
                style={{ 
                    width: 128, height: 128, borderRadius: 64, alignItems: 'center', justifyContent: 'center',
                    backgroundColor: status === 'connected' ? '#2563eb' : '#374151',
                    shadowColor: '#2563eb',
                    shadowOffset: { width: 0, height: 0 },
                    shadowOpacity: 0.8,
                    shadowRadius: 20 + (volume * 30),
                    elevation: 10,
                    transform: [{ scale: status === 'connected' ? 1 + (volume * 0.2) : 1 }]
                }}
            >
               {status === 'connecting' ? (
                   <ActivityIndicator size="large" color="#ffffff" />
               ) : (
                   <View style={{ width: 16, height: 16, backgroundColor: 'white', borderRadius: 8 }} />
               )}
            </View>

            <View style={{ alignItems: 'center' }}>
              <Text style={{ color: 'white', fontSize: 24, fontWeight: 'bold', marginBottom: 8 }}>Live Voice Chat</Text>
              <Text style={{ color: '#9ca3af', textAlign: 'center' }}>
                {status === 'connecting' ? 'Connecting to Gemini...' : 
                 status === 'connected' ? 'Listening...' : 'Connection Error'}
              </Text>

              <Text style={{ color: '#4b5563', fontSize: 12, marginTop: 32, textAlign: 'center', paddingHorizontal: 32 }}>
                * Real-time audio streaming requires native 'expo-av' recording setup. UI Mode Only.
              </Text>
            </View>
         </View>
      </View>
    </Modal>
  );
};

